import{_ as o,o as d,c,a2 as i}from"./chunks/framework.QoSTM79V.js";const h=JSON.parse('{"title":"后端 API 规范","description":"","frontmatter":{},"headers":[],"relativePath":"mango-pmo/rules/backend/03-api.md","filePath":"mango-pmo/rules/backend/03-api.md"}'),l={name:"mango-pmo/rules/backend/03-api.md"};function a(t,e,r,n,u,s){return d(),c("div",null,[...e[0]||(e[0]=[i('<h1 id="后端-api-规范" tabindex="-1">后端 API 规范 <a class="header-anchor" href="#后端-api-规范" aria-label="Permalink to &quot;后端 API 规范&quot;">​</a></h1><h2 id="_1-基本规则" tabindex="-1">1. 基本规则 <a class="header-anchor" href="#_1-基本规则" aria-label="Permalink to &quot;1. 基本规则&quot;">​</a></h2><ul><li>API 只暴露协议模型。</li><li>不暴露 <code>Entity</code>、<code>PO</code>。</li><li>写操作使用 <code>Command</code>。</li><li>查询使用 <code>Query</code>。</li><li>返回统一使用 <code>VO</code>。</li></ul><h2 id="_2-入参规则" tabindex="-1">2. 入参规则 <a class="header-anchor" href="#_2-入参规则" aria-label="Permalink to &quot;2. 入参规则&quot;">​</a></h2><ul><li>创建使用 <code>CreateXxxCommand</code>。</li><li>更新使用 <code>UpdateXxxCommand</code>。</li><li>查询使用 <code>XxxQuery</code> 或 <code>XxxPageQuery</code>。</li><li>简单路径参数和查询参数在 1-2 个时可以直接放方法签名。</li><li>客户端可传入参数超过 2 个时必须收敛为 <code>Command</code>、<code>Query</code> 或专用请求对象；<code>HttpServletRequest</code>、<code>HttpServletResponse</code> 等服务端上下文对象不计入客户端入参数量。</li><li><code>GET</code> 禁止使用 <code>@RequestBody</code>；复杂 <code>Query</code> 对象必须使用 <code>@ParameterObject</code> 展开为 query 参数，禁止在 OpenAPI/Knife4j 中显示为 <code>query={...}</code> JSON 字符串参数。</li><li><code>POST</code> / <code>PUT</code> / <code>PATCH</code> 的 <code>Command</code>、<code>PO</code>、请求对象默认使用 <code>@RequestBody</code> 接收 JSON；只有明确声明为表单提交的接口才允许使用 <code>@RequestParam</code> / <code>@ModelAttribute</code>。</li><li><code>DELETE</code> 的简单标识优先使用 <code>@RequestParam</code>；批量删除等复杂命令使用 <code>@RequestBody</code>。</li><li>API 参数必须使用 Bean Validation 校验。</li><li><code>Command</code>、<code>Query</code> 字段必须声明 <code>jakarta.validation</code> 约束注解。</li><li>路径参数和查询参数必须声明校验约束。</li><li>Controller 或 <code>Api</code> 必须使用 <code>@Validated</code> 或等效机制开启参数校验。</li></ul><h2 id="_2-1-service-入参规则" tabindex="-1">2.1 Service 入参规则 <a class="header-anchor" href="#_2-1-service-入参规则" aria-label="Permalink to &quot;2.1 Service 入参规则&quot;">​</a></h2><ul><li><code>XxxApi</code>、Controller、<code>IXxxService</code> 和 <code>XxxServiceImpl</code> 的核心业务方法必须保持同一入参模型。</li><li>创建、更新、查询、批量操作和复杂业务动作必须使用 <code>Command</code>、<code>Query</code> 或专用请求对象。</li><li>Service 方法超过 2 个业务字段入参时，必须收敛为 <code>Command</code>、<code>Query</code> 或专用请求对象。</li><li>允许直接展开的参数仅限 <code>id</code>、状态枚举、布尔控制位等 1-2 个简单控制参数。</li><li>Controller 调 Service 时直接传 <code>Command</code>、<code>Query</code> 或专用请求对象；Service 负责校验后的业务编排和模型转换。</li><li>Service 调 Mapper 时不得继续传 API 协议模型，必须转换为 Entity、id、Wrapper、分页对象或 core 内部持久化查询对象。</li></ul><h2 id="_2-2-文件字段规则" tabindex="-1">2.2 文件字段规则 <a class="header-anchor" href="#_2-2-文件字段规则" aria-label="Permalink to &quot;2.2 文件字段规则&quot;">​</a></h2><ul><li>业务 API 的创建、更新入参禁止接收需要持久化的文件访问地址字段，例如 <code>url</code>、<code>previewUrl</code>、<code>downloadUrl</code>、<code>directPreviewUrl</code>、<code>directDownloadUrl</code>。</li><li>业务 API 应接收文件中心标识字段，例如 <code>fileId</code>、<code>fileIds</code>、<code>attachmentIds</code>、<code>iconFileId</code>，或明确的 <code>mango-file:{id}</code> token。</li><li>业务 VO 可以返回文件 ID；如页面需要临时预览或下载地址，由前端通过 <code>mango-file</code> 查询，或由业务聚合层在响应时临时组装，禁止反写到业务表。</li><li>预签名 URL、对象存储直连地址只允许作为单次响应中的运行时字段，不允许成为业务 Command、Entity 或持久化 JSON 的字段。</li></ul><h2 id="_2-1-openapi-knife4j-文档规则" tabindex="-1">2.1 OpenAPI / Knife4j 文档规则 <a class="header-anchor" href="#_2-1-openapi-knife4j-文档规则" aria-label="Permalink to &quot;2.1 OpenAPI / Knife4j 文档规则&quot;">​</a></h2><ul><li>所有对外展示的 Controller 必须声明中文 <code>@Tag(name, description)</code>，禁止显示默认的 <code>xxx-controller</code>。</li><li>所有 HTTP 接口方法必须声明中文 <code>@Operation(summary, description)</code>；<code>summary</code> 说明接口动作，<code>description</code> 说明业务语义、访问边界或关键约束。</li><li>所有客户端可传入参数都必须在文档中展示中文含义。</li><li>所有简单请求参数必须声明中文 <code>@Parameter(description = &quot;...&quot;)</code>，包括 <code>@RequestParam</code>、<code>@RequestHeader</code>、<code>@PathVariable</code>（路径变量本身禁止新增）。</li><li>所有 <code>Command</code>、<code>Query</code>、<code>Request</code>、<code>Response</code>、<code>VO</code>、<code>PO</code>、<code>DTO</code> 字段必须声明中文 <code>@Schema(description = &quot;...&quot;)</code>；字段含义、枚举值或取值约束要能在文档中直接看懂。</li><li><code>GET</code> Query 对象在 Controller 方法参数上必须使用 <code>@ParameterObject</code>，并依赖字段级 <code>@Schema</code> 展示中文参数含义。</li><li><code>POST</code> / <code>PUT</code> JSON body 的 Controller 参数必须使用 <code>@RequestBody</code>，并依赖请求对象字段级 <code>@Schema</code> 展示中文字段含义。</li><li>鉴权文档使用名为 <code>Authorization</code> 的 header apiKey 安全方案；Knife4j 调试时输入完整 <code>Bearer &lt;accessToken&gt;</code>，请求必须发出标准 <code>Authorization</code> 请求头。</li><li>内部接口可以在 <code>@Operation(description)</code> 中说明“仅内部调用”；是否显示对内 tag 由文档配置控制，不允许为了文档展示修改真实访问权限。</li></ul><h2 id="_3-返回规则" tabindex="-1">3. 返回规则 <a class="header-anchor" href="#_3-返回规则" aria-label="Permalink to &quot;3. 返回规则&quot;">​</a></h2><ul><li>无数据成功：<code>R&lt;Void&gt;</code></li><li>单对象：<code>R&lt;XxxVO&gt;</code></li><li>列表：<code>R&lt;List&lt;XxxVO&gt;&gt;</code></li><li>分页：<code>R&lt;PageResult&lt;XxxVO&gt;&gt;</code></li><li>简单状态：<code>R&lt;Boolean&gt;</code></li><li>简单标识：<code>R&lt;Long&gt;</code>、<code>R&lt;String&gt;</code></li></ul><h2 id="_3-1-数据来源规则" tabindex="-1">3.1 数据来源规则 <a class="header-anchor" href="#_3-1-数据来源规则" aria-label="Permalink to &quot;3.1 数据来源规则&quot;">​</a></h2><ul><li>API 返回的数据必须来自数据库、配置、枚举契约、字典服务、远程 API 或明确的运行时计算。</li><li>本应由数据库维护的数据，禁止在 Controller、Service、Converter 或 VO 组装逻辑中写死。</li><li>菜单、权限、公共路径、租户默认数据、字典、业务状态、流程配置、计费规则等可运营数据必须有数据库、migration、配置中心或后台维护入口。</li><li>临时调试数据和 mock 数据禁止进入最终 API 实现。</li><li>接口尚未接入真实数据源时，必须标记为未完成或阻塞，禁止声明可供前端替换 mock。</li></ul><h2 id="_4-分层规则" tabindex="-1">4. 分层规则 <a class="header-anchor" href="#_4-分层规则" aria-label="Permalink to &quot;4. 分层规则&quot;">​</a></h2><ul><li><code>api</code> 只放 <code>XxxApi</code>、<code>command</code>、<code>query</code>、<code>vo</code>、<code>enums</code>。</li><li><code>api</code> 如需声明内部访问边界，允许依赖 <code>mango-infra-web-api</code> 并在 <code>XxxApi</code> 类或方法上使用 <code>@Inner</code>。</li><li><code>api</code> 禁止依赖 <code>mango-infra-web-starter</code>。</li><li>Controller 只做协议适配。</li><li>Controller 必须实现对应 <code>XxxApi</code>，内部只能依赖 <code>IXxxService</code> 或等效服务接口。</li><li>Controller 禁止持有 <code>XxxApi</code> 字段进行自调用。</li><li>Controller 不直接操作 <code>Mapper</code>。</li><li>Controller 不直接返回持久化对象。</li><li><code>XxxApi</code> 只定义能力契约。</li><li><code>XxxApi</code> 禁止声明 <code>@FeignClient</code>。</li><li><code>XxxService</code> 禁止直接实现 <code>XxxApi</code>；服务层应实现 <code>IXxxService</code>。</li></ul><h2 id="_5-dto-规则" tabindex="-1">5. DTO 规则 <a class="header-anchor" href="#_5-dto-规则" aria-label="Permalink to &quot;5. DTO 规则&quot;">​</a></h2><ul><li>仓内业务 API 禁止使用 <code>DTO</code> 作为默认入参或返回命名。</li><li><code>DTO</code> 只允许用于第三方集成、外部回调、历史兼容层。</li></ul><h2 id="_6-兼容策略" tabindex="-1">6. 兼容策略 <a class="header-anchor" href="#_6-兼容策略" aria-label="Permalink to &quot;6. 兼容策略&quot;">​</a></h2><ul><li>新增接口必须遵守本规范。</li><li>老接口按模块逐步迁移。</li><li>迁移期间允许在 service 或 convert 层做兼容转换。</li><li>不允许继续新增 <code>DTO</code>、<code>PO</code>、<code>Entity</code> 直出直入接口。</li></ul><h2 id="_7-禁止事项" tabindex="-1">7. 禁止事项 <a class="header-anchor" href="#_7-禁止事项" aria-label="Permalink to &quot;7. 禁止事项&quot;">​</a></h2><ul><li><code>@RequestBody XxxEntity</code></li><li><code>R&lt;XxxEntity&gt;</code></li><li><code>R&lt;PageResult&lt;XxxEntity&gt;&gt;</code></li><li><code>UserDTO</code> 作为仓内业务 API 返回</li><li><code>Map&lt;String, Object&gt;</code> 作为通用业务接口模型</li><li>无校验注解的 <code>Command</code> / <code>Query</code></li><li>API 参数绕过 Bean Validation 直接进入业务层</li><li>在 <code>*-api</code> 中写 <code>@FeignClient</code></li><li>在 API 契约中硬编码服务发现名</li><li>业务 API 用文件访问地址代替文件 ID</li><li>API 写死本应来自数据库、配置、字典服务或真实接口的数据</li></ul>',23)])])}const p=o(l,[["render",a]]);export{h as __pageData,p as default};
